{
  "sentences": [
    {
      "text": "你要塑膠袋嗎？",
      "pinyin": "Nǐ yào sùjiāodài ma?",
      "pinyin_numeric": "ni3 yao4 su4jiao1dai4 ma0",
      "translation_en": "Do you want a plastic bag?",
      "translation_ko": "비닐봉지 필요하세요?"
    },
    {
      "text": "要不要環保袋？",
      "pinyin": "Yào bù yào huánbǎo dài?",
      "pinyin_numeric": "yao4 bu4 yao4 huan2bao3 dai4",
      "translation_en": "Do you want an eco-friendly bag or not?",
      "translation_ko": "에코백 필요하세요?"
    },
    {
      "text": "你要收據嗎？",
      "pinyin": "Nǐ yào shōujù ma?",
      "pinyin_numeric": "ni3 yao4 shou1ju4 ma0",
      "translation_en": "Do you want a receipt?",
      "translation_ko": "영수증 필요하세요?"
    },
    {
      "text": "要不要載具？",
      "pinyin": "Yào bù yào zàijù?",
      "pinyin_numeric": "yao4 bu4 yao4 zai4ju4",
      "translation_en": "Do you want an invoice carrier or not?",
      "translation_ko": "인보이스 캐리어 필요하세요?"
    },
    {
      "text": "你要用現金嗎？",
      "pinyin": "Nǐ yào yòng xiànjīn ma?",
      "pinyin_numeric": "ni3 yao4 yong4 xian4jin1 ma0",
      "translation_en": "Do you want to pay with cash?",
      "translation_ko": "현금으로 계산하시겠어요?"
    },
    {
      "text": "要不要刷卡？",
      "pinyin": "Yào bù yào shuākǎ?",
      "pinyin_numeric": "yao4 bu4 yao4 shua1ka3",
      "translation_en": "Do you want to pay by card or not?",
      "translation_ko": "카드로 결제하시겠어요?"
    },
    {
      "text": "你要加熱便當嗎？",
      "pinyin": "Nǐ yào jiārè biàndāng ma?",
      "pinyin_numeric": "ni3 yao4 jia1re4 bian4dang1 ma0",
      "translation_en": "Do you want to heat the bento?",
      "translation_ko": "도시락을 데워 드릴까요?"
    },
    {
      "text": "要不要買一送一？",
      "pinyin": "Yào bù yào mǎi yī sòng yī?",
      "pinyin_numeric": "yao4 bu4 yao4 mai3 yi1 song4 yi1",
      "translation_en": "Do you want the buy-one-get-one-free deal or not?",
      "translation_ko": "하나 사면 하나 더 주는 행사 하실래요?"
    },
    {
      "text": "你要茶葉蛋嗎？",
      "pinyin": "Nǐ yào cháyèdàn ma?",
      "pinyin_numeric": "ni3 yao4 cha2ye4dan4 ma0",
      "translation_en": "Do you want a tea egg?",
      "translation_ko": "차이예단 드릴까요?"
    },
    {
      "text": "要不要加珍珠？",
      "pinyin": "Yào bù yào jiā zhēnzhū?",
      "pinyin_numeric": "yao4 bu4 yao4 jia1 zhen1zhu1",
      "translation_en": "Do you want to add boba or not?",
      "translation_ko": "타피오카 펄 추가하시겠어요?"
    }
  ]
}
